import{_ as d,o as r,c as a,a1 as e}from"./chunks/framework.DXL1AtGc.js";const h="/diagrams/latium-tiers.svg",o="/diagrams/albion-tiers.svg",g=JSON.parse('{"title":"住民層","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/population.md","filePath":"wiki/population.md"}'),i={name:"wiki/population.md"};function n(l,t,s,b,p,c){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="住民層" tabindex="-1">住民層 <a class="header-anchor" href="#住民層" aria-label="Permalink to &quot;住民層&quot;">​</a></h1><p>Anno 117 には**ラティウム（ローマ）<strong>と</strong>アルビオン（ケルト）**の2系統の住民層があります。</p><h2 id="ニーズシステムの仕組み" tabindex="-1">ニーズシステムの仕組み <a class="header-anchor" href="#ニーズシステムの仕組み" aria-label="Permalink to &quot;ニーズシステムの仕組み&quot;">​</a></h2><ul><li><strong>カテゴリ制:</strong> 各層に食料・ファッション・家庭・公共などのカテゴリがあり、各カテゴリから1品以上を充足することで上位層へ昇格できます</li><li><strong>OR 選択:</strong> 同一カテゴリ内の複数品目は「いずれか1品で充足」。複数供給すると住民の選好により分散消費されます</li><li><strong>累積消費:</strong> 上位層の住民も下位層の財を引き続き消費します</li></ul><hr><h2 id="ラティウム住民層" tabindex="-1">ラティウム住民層 <a class="header-anchor" href="#ラティウム住民層" aria-label="Permalink to &quot;ラティウム住民層&quot;">​</a></h2><p><img src="'+h+'" alt="ラティウム住民層の進化"></p><h3 id="リベルトゥス" tabindex="-1">リベルトゥス <a class="header-anchor" href="#リベルトゥス" aria-label="Permalink to &quot;リベルトゥス&quot;">​</a></h3><p>ラティウムの最下層住民。ゲーム開始時から存在する基本労働力。</p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>イワシ（必須）、お粥</td></tr><tr><td>ファッション</td><td>チュニック、ピレウス帽</td></tr><tr><td>公共サービス</td><td>市場、酒場</td></tr></tbody></table><hr><h3 id="プレブス" tabindex="-1">プレブス <a class="header-anchor" href="#プレブス" aria-label="Permalink to &quot;プレブス&quot;">​</a></h3><p>リベルトゥスのニーズを充足後にアップグレード可能。</p><p><strong>追加ニーズ（プレブス固有）:</strong></p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>パン、ガルム</td></tr><tr><td>ファッション</td><td>サンダル、石鹸</td></tr><tr><td>家庭</td><td>アンフォラ、オリーブオイル</td></tr><tr><td>公共サービス</td><td>聖域、ラテン語学校</td></tr></tbody></table><hr><h3 id="エクィテス" tabindex="-1">エクィテス <a class="header-anchor" href="#エクィテス" aria-label="Permalink to &quot;エクィテス&quot;">​</a></h3><p>プレブスのニーズを充足後にアップグレード可能。</p><p><strong>追加ニーズ（エクィテス固有）:</strong></p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>ワイン、チーズ</td></tr><tr><td>ファッション</td><td>トガ、ブローチ</td></tr><tr><td>家庭</td><td>筆記板、高級ガラス、小像</td></tr><tr><td>公共サービス</td><td>貯水池、劇場、賭博場</td></tr></tbody></table><hr><h3 id="パトリキ" tabindex="-1">パトリキ <a class="header-anchor" href="#パトリキ" aria-label="Permalink to &quot;パトリキ&quot;">​</a></h3><p>エクィテスのニーズを充足後にアップグレード可能。最高税収・威信を誇る最上位層。</p><p><strong>追加ニーズ（パトリキ固有）:</strong></p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>牡蠣のキャビア添え、鳥舌肉アスピック</td></tr><tr><td>ファッション</td><td>ネックレス、外套</td></tr><tr><td>家庭</td><td>肘掛け椅子、手鏡</td></tr></tbody></table><hr><h2 id="アルビオン住民層" tabindex="-1">アルビオン住民層 <a class="header-anchor" href="#アルビオン住民層" aria-label="Permalink to &quot;アルビオン住民層&quot;">​</a></h2><p>アルビオンでは Tier 2 以降に<strong>ケルト文化</strong>と<strong>ローマ文化</strong>の2つの路線があります。</p><p><img src="'+o+'" alt="アルビオン住民層の進化"></p><h3 id="ウェーダー" tabindex="-1">ウェーダー <a class="header-anchor" href="#ウェーダー" aria-label="Permalink to &quot;ウェーダー&quot;">​</a></h3><p>アルビオンの共通基本層。文化選択前の住民。</p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>ザル貝（必須）、ウナギ（必須）</td></tr><tr><td>ファッション</td><td>チュニック、葦の靴</td></tr><tr><td>公共サービス</td><td>市場、吟遊詩人の暖炉</td></tr></tbody></table><hr><h3 id="スミス-ケルト文化路線" tabindex="-1">スミス（ケルト文化路線） <a class="header-anchor" href="#スミス-ケルト文化路線" aria-label="Permalink to &quot;スミス（ケルト文化路線）&quot;">​</a></h3><p>ウェーダーがケルト文化を選択した場合に進化。</p><p><strong>追加ニーズ（スミス固有）:</strong></p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>チーズ、ビール</td></tr><tr><td>ファッション</td><td>ズボン、首輪</td></tr><tr><td>家庭</td><td>角杯、部族の盾</td></tr><tr><td>公共サービス</td><td>運動場、聖所</td></tr></tbody></table><hr><h3 id="アルダー-ケルト文化路線" tabindex="-1">アルダー（ケルト文化路線） <a class="header-anchor" href="#アルダー-ケルト文化路線" aria-label="Permalink to &quot;アルダー（ケルト文化路線）&quot;">​</a></h3><p>スミスのニーズを充足後にアップグレード可能。ケルト文化の長老・指導者層。</p><p><strong>追加ニーズ（アルダー固有）:</strong></p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>ローストビーフ、ワイン</td></tr><tr><td>ファッション</td><td>外套、毛皮の帽子</td></tr><tr><td>家庭</td><td>戦車、高級ガラス</td></tr><tr><td>公共サービス</td><td>厠所、市議会、劇場、賭博場</td></tr><tr><td>脅威</td><td>塚、神聖な森</td></tr></tbody></table><hr><h3 id="メルカトル-ローマ文化路線" tabindex="-1">メルカトル（ローマ文化路線） <a class="header-anchor" href="#メルカトル-ローマ文化路線" aria-label="Permalink to &quot;メルカトル（ローマ文化路線）&quot;">​</a></h3><p>ウェーダーがローマ文化を選択した場合に進化。</p><p><strong>追加ニーズ（メルカトル固有）:</strong></p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>パン、ソーセージ</td></tr><tr><td>ファッション</td><td>ブローチ、石鹸</td></tr><tr><td>家庭</td><td>アンフォラ、オリーブオイル</td></tr><tr><td>公共サービス</td><td>ラテン語学校、聖所</td></tr></tbody></table><hr><h3 id="ノビレス-ローマ文化路線" tabindex="-1">ノビレス（ローマ文化路線） <a class="header-anchor" href="#ノビレス-ローマ文化路線" aria-label="Permalink to &quot;ノビレス（ローマ文化路線）&quot;">​</a></h3><p>メルカトルのニーズを充足後にアップグレード可能。ローマ貴族文化に傾倒した上流層。</p><p><strong>追加ニーズ（ノビレス固有）:</strong></p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>商品・施設</th></tr></thead><tbody><tr><td>食料</td><td>鳥舌肉アスピック、ワイン</td></tr><tr><td>ファッション</td><td>かつら、トガ</td></tr><tr><td>家庭</td><td>手鏡、高級ガラス</td></tr><tr><td>公共サービス</td><td>貯水池、劇場、賭博場</td></tr><tr><td>脅威</td><td>神殿、浴場</td></tr></tbody></table>',52)])])}const m=d(i,[["render",n]]);export{g as __pageData,m as default};
